arguments.content:
const { Sketch, Page, Artboard, Rectangle, Text, Group } = require('sketch-constructor');
const path = require('path');

const WIDTH = 1440;
const SECTIONS = [
  { name: 'Header Bar', h: 40, bg: '#1e2933', text: '#fff' },
  { name: 'Main Nav', h: 80, bg: '#3776ab', text: '#fff' },
  { name: 'Hero Banner', h: 380, bg: '#2b5b84', text: '#fff' },
  { name: 'Features Grid', h: 280, bg: '#f7f7f7', text: '#333' },
  { name: 'News & Events', h: 360, bg: '#ffffff', text: '#333' },
  { name: 'Success Stories', h: 200, bg: '#f7f7f7', text: '#333' },
  { name: 'Use Python For', h: 300, bg: '#ffffff', text: '#333' },
  { name: 'PSF Banner', h: 180, bg: '#3776ab', text: '#fff' },
  { name: 'Footer', h: 260, bg: '#1e2933', text: '#ccc' },
];

let y = 0;
const totalHeight = SECTIONS.reduce((sum, s) => sum + s.h, 0);

const sketch = new Sketch();
const page = new Page({ name: 'Python.org Desktop' });
const artboard = new Artboard({
  name: 'Desktop 1440px',
  frame: { x: 0, y: 0, width: WIDTH, height: totalHeight },
  backgroundColor: '#ffffff',
});

// Add section rectangles
SECTIONS.forEach((sec) => {
  const rect = new Rectangle({
    name: sec.name,
    x: 0,
    y: y,
    width: WIDTH,
    height: sec.h,
    style: {
      fills: [{ color: sec.bg, fillType: 0, isEnabled: true }],
    },
  });
  artboard.addLayer(rect);

  // Add label text inside each section
  const label = new Text({
    name: `${sec.name} Label`,
    string: sec.name,
    fontSize: 18,
    fontName: 'SourceSansPro-Bold',
    color: sec.text,
    frame: { x: 40, y: y + 20, width: 300, height: 30 },
  });
  artboard.addLayer(label);

  y += sec.h;
});

// Hero tagline text
const heroTagline = new Text({
  name: 'Hero Tagline',
  string: 'Python is a programming language that lets you work quickly and integrate systems more effectively.',
  fontSize: 24,
  fontName: 'SourceSansPro-Regular',
  color: '#ffffff',
  frame: { x: 60, y: 180, width: 600, height: 80 },
});
artboard.addLayer(heroTagline);

// Hero code block background (dark rectangle)
const codeBlock = new Rectangle({
  name: 'Code Block',
  x: 700,
  y: 140,
  width: 640,
  height: 260,
  style: {
    fills: [{ color: '#0d1117', fillType: 0, isEnabled: true }],
  },
});
artboard.addLayer(codeBlock);

// Code text
const codeText = new Text({
  name: 'Code Example',
  string: '# Simple arithmetic\n>>> 1 / 2\n0.5\n>>> 2 ** 3\n8\n>>> 17 / 3  # true division\n5.666666666666667\n>>> 17 // 3  # floor division\n5',
  fontSize: 14,
  fontName: 'Monaco',
  color: '#e6edf3',
  frame: { x: 720, y: 160, width: 600, height: 220 },
});
artboard.addLayer(codeText);

// Feature titles
const featureTitles = ['Get Started', 'Download', 'Docs', 'Jobs'];
featureTitles.forEach((title, i) => {
  const fx = 40 + i * 350;
  const ftext = new Text({
    name: `Feature ${title}`,
    string: title,
    fontSize: 22,
    fontName: 'SourceSansPro-Bold',
    color: '#3776ab',
    frame: { x: fx, y: 520, width: 300, height: 30 },
  });
  artboard.addLayer(ftext);
});

// News / Events headings
const newsTitle = new Text({
  name: 'Latest News',
  string: 'Latest News',
  fontSize: 20,
  fontName: 'SourceSansPro-Bold',
  color: '#333333',
  frame: { x: 40, y: 820, width: 300, height: 30 },
});
artboard.addLayer(newsTitle);

const eventsTitle = new Text({
  name: 'Upcoming Events',
  string: 'Upcoming Events',
  fontSize: 20,
  fontName: 'SourceSansPro-Bold',
  color: '#333333',
  frame: { x: 760, y: 820, width: 300, height: 30 },
});
artboard.addLayer(eventsTitle);

// Footer columns
const footerCols = ['About', 'Downloads', 'Documentation', 'Community', 'Success Stories', 'News', 'Events', 'Contributing'];
footerCols.forEach((col, i) => {
  const fx = 40 + i * 170;
  const fcol = new Text({
    name: `Footer ${col}`,
    string: col,
    fontSize: 14,
    fontName: 'SourceSansPro-Bold',
    color: '#ffffff',
    frame: { x: fx, y: totalHeight - 200, width: 150, height: 20 },
  });
  artboard.addLayer(fcol);
});

page.addArtboard(artboard);
sketch.addPage(page);

const outputPath = path.resolve('[workspace-path]');
sketch.build(outputPath).then(() => {
  console.log('Sketch file created at', outputPath);
}).catch((err) => {
  console.error('Error building sketch file:', err);
});

